// AUTO-GENERADO — imágenes de elevadores en base64 para react-pdf
// Generado desde public/pdf/*.png

export const ELEVATOR_IMAGES: Record<string, string> = {
  'elevator-mrl-g': 'data:image/png;base64,',
  'elevator-mrl-l': 'data:image/png;base64,',
  'elevator-mr': 'data:image/png;base64,',
  'elevator-hyd': 'data:image/png;base64,',
};

export const getElevatorImage = (model: string): string => {
  const map: Record<string, string> = {
    'MRL-G':     ELEVATOR_IMAGES['elevator-mrl-g'],
    'MRL-L':     ELEVATOR_IMAGES['elevator-mrl-l'],
    'MR':        ELEVATOR_IMAGES['elevator-mr'],
    'HYD':       ELEVATOR_IMAGES['elevator-hyd'],
    'Home Lift': ELEVATOR_IMAGES['elevator-hyd'],
  };
  return map[model] || ELEVATOR_IMAGES['elevator-mr'];
};
